import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Sentence {
  id: string;
  date: string; // YYYY-MM-DD
  sentence: string;
  meaning: string;
  hint: string;
  referenceUrl: string;
  bookmark: boolean;
  createdAt: string;
}

export type ViewType = 'all' | 'date' | 'bookmark' | 'streak';

export interface AppState {
  sentences: Sentence[];
  loading: boolean;
  error: string | null;
}

/**
 * INSTRUCTIONS:
 * 1. Open a Google Sheet.
 * 2. Go to Extensions > Apps Script.
 * 3. Replace the code with this snippet.
 * 4. Click 'Deploy' > 'New Deployment' > 'Web App'.
 * 5. Set 'Who has access' to 'Anyone'.
 * 6. Copy the URL and paste it into `services/apiService.ts` in your React app.
 */

const SHEET_NAME = "Sentences";

function setup() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_NAME);
  if (!sheet) {
    sheet = ss.insertSheet(SHEET_NAME);
    sheet.appendRow(["id", "date", "sentence", "meaning", "hint", "referenceUrl", "bookmark", "createdAt"]);
  }
}

function doGet(e) {
  const action = e.parameter.action;
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_NAME);
  const data = sheet.getDataRange().getValues();
  const headers = data[0];
  const rows = data.slice(1);

  const jsonData = rows.map(row => {
    let obj = {};
    headers.forEach((header, i) => {
      obj[header] = row[i];
    });
    // Ensure types
    obj.bookmark = (obj.bookmark === true || obj.bookmark === "true" || obj.bookmark === "TRUE");
    return obj;
  });

  return ContentService.createTextOutput(JSON.stringify(jsonData))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  const body = JSON.parse(e.postData.contents);
  const action = body.action;
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_NAME);
  const data = sheet.getDataRange().getValues();
  const headers = data[0];

  if (action === "upsert") {
    const item = body.data;
    let rowIndex = -1;

    if (item.id) {
      for (let i = 1; i < data.length; i++) {
        if (data[i][0] == item.id) {
          rowIndex = i + 1;
          break;
        }
      }
    }

    const id = item.id || Utilities.getUuid();
    const rowData = [
      id,
      item.date || new Date().toISOString().split('T')[0],
      item.sentence || "",
      item.meaning || "",
      item.hint || "",
      item.referenceUrl || "",
      item.bookmark || false,
      item.createdAt || new Date().toISOString()
    ];

    if (rowIndex > 0) {
      sheet.getRange(rowIndex, 1, 1, rowData.length).setValues([rowData]);
    } else {
      sheet.appendRow(rowData);
    }
    return ContentService.createTextOutput(JSON.stringify({ success: true, id: id }))
      .setMimeType(ContentService.MimeType.JSON);

  } else if (action === "delete") {
    const id = body.id;
    for (let i = 1; i < data.length; i++) {
      if (data[i][0] == id) {
        sheet.deleteRow(i + 1);
        break;
      }
    }
    return ContentService.createTextOutput(JSON.stringify({ success: true }))
      .setMimeType(ContentService.MimeType.JSON);

  } else if (action === "toggleBookmark") {
    const id = body.id;
    let currentVal = false;
    for (let i = 1; i < data.length; i++) {
      if (data[i][0] == id) {
        currentVal = (data[i][6] === true || data[i][6] === "true" || data[i][6] === "TRUE");
        sheet.getRange(i + 1, 7).setValue(!currentVal);
        break;
      }
    }
    return ContentService.createTextOutput(JSON.stringify({ success: true, bookmark: !currentVal }))
      .setMimeType(ContentService.MimeType.JSON);
  }

  return ContentService.createTextOutput(JSON.stringify({ success: false, error: "Invalid action" }))
    .setMimeType(ContentService.MimeType.JSON);
}

import { Sentence } from '../types';

// IMPORTANT: Replace this with your deployed Google Apps Script Web App URL
const API_URL = "https://script.google.com/macros/s/YOUR_DEPLOYED_GAS_URL_HERE/exec";

export const apiService = {
  async fetchSentences(): Promise<Sentence[]> {
    if (API_URL.includes("YOUR_DEPLOYED_GAS_URL_HERE")) {
      console.warn("API URL not configured. Returning mock data.");
      return this.getMockData();
    }
    try {
      const response = await fetch(API_URL);
      if (!response.ok) throw new Error("Failed to fetch data");
      return await response.json();
    } catch (err) {
      console.error(err);
      return this.getMockData(); // Fallback for demo
    }
  },

  async upsertSentence(sentence: Partial<Sentence>): Promise<any> {
    return this.post({ action: 'upsert', data: sentence });
  },

  async deleteSentence(id: string): Promise<any> {
    return this.post({ action: 'delete', id });
  },

  async toggleBookmark(id: string): Promise<any> {
    return this.post({ action: 'toggleBookmark', id });
  },

  async post(body: any): Promise<any> {
    if (API_URL.includes("YOUR_DEPLOYED_GAS_URL_HERE")) {
      return { success: true };
    }
    try {
      // GAS requires no-cors for simple POST or standard CORS setup. 
      // Using 'follow' is important for GAS redirects.
      const response = await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors', // In many environments GAS works best with no-cors or standard redirect handling
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      return { success: true }; // with no-cors we can't read the response body easily
    } catch (err) {
      console.error(err);
      throw err;
    }
  },

  getMockData(): Sentence[] {
    return [
      {
        id: '1',
        date: new Date().toISOString().split('T')[0],
        sentence: 'The journey of a thousand miles begins with a single step.',
        meaning: '천 리 길도 한 걸음부터.',
        hint: 'Starts with "The journey"',
        referenceUrl: 'https://example.com',
        bookmark: true,
        createdAt: new Date().toISOString()
      },
      {
        id: '2',
        date: new Date(Date.now() - 86400000).toISOString().split('T')[0],
        sentence: 'Practice makes perfect.',
        meaning: '연습이 완벽을 만든다.',
        hint: 'Consistency is key',
        referenceUrl: '',
        bookmark: false,
        createdAt: new Date().toISOString()
      }
    ];
  }
};

import React, { useState, useEffect, createContext, useContext } from 'react';
import { HashRouter, Routes, Route, useNavigate } from 'react-router-dom';
import { Sentence, AppState } from './types';
import { apiService } from './services/apiService';

import MainView from './views/MainView';
import ListView from './views/ListView';
import InputView from './views/InputView';
import StudyView from './views/StudyView';

interface AppContextType {
  state: AppState;
  refreshData: () => Promise<void>;
  updateBookmarkOptimistically: (id: string) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    sentences: [],
    loading: true,
    error: null,
  });

  const refreshData = async () => {
    setState(prev => ({ ...prev, loading: true }));
    try {
      const data = await apiService.fetchSentences();
      setState({ sentences: data, loading: false, error: null });
    } catch (err) {
      setState(prev => ({ ...prev, loading: false, error: "Failed to load data" }));
    }
  };

  const updateBookmarkOptimistically = (id: string) => {
    setState(prev => ({
      ...prev,
      sentences: prev.sentences.map(s => s.id === id ? { ...s, bookmark: !s.bookmark } : s)
    }));
    apiService.toggleBookmark(id).catch(() => {
      // Revert if failed (optional complexity)
      console.error("Failed to update bookmark on server");
    });
  };

  useEffect(() => {
    refreshData();
  }, []);

  return (
    <AppContext.Provider value={{ state, refreshData, updateBookmarkOptimistically }}>
      <HashRouter>
        <div className="min-h-screen max-w-md mx-auto bg-white shadow-xl relative overflow-x-hidden">
          <Routes>
            <Route path="/" element={<MainView />} />
            <Route path="/list/:type/:value" element={<ListView />} />
            <Route path="/input" element={<InputView />} />
            <Route path="/edit/:id" element={<InputView />} />
            <Route path="/study" element={<StudyView />} />
          </Routes>
        </div>
      </HashRouter>
    </AppContext.Provider>
  );
};

export default App;

