import React from 'react';
import Calendar from 'react-calendar';
import { Plus, Shuffle, PlayCircle } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useApp } from '../App';
import { Header, LoadingOverlay } from '../components/Layout';
import StatsDashboard from '../components/StatsDashboard';

const MainView: React.FC = () => {
  const { state } = useApp();
  const navigate = useNavigate();

  const getDaySentences = (date: Date) => {
    const dateStr = date.toISOString().split('T')[0];
    return state.sentences.filter(s => s.date === dateStr);
  };

  const tileContent = ({ date, view }: { date: Date, view: string }) => {
    if (view === 'month') {
      const daySentences = getDaySentences(date);
      if (daySentences.length > 0) {
        return <div className="dot-indicator"></div>;
      }
    }
    return null;
  };

  const handleDateClick = (date: Date) => {
    const dateStr = date.toISOString().split('T')[0];
    navigate(`/list/date/${dateStr}`);
  };

  const handleRandomStudy = () => {
    if (state.sentences.length === 0) return;
    const shuffled = [...state.sentences].sort(() => 0.5 - Math.random());
    const selected = shuffled.slice(0, 10);
    // Passing state via session storage or state is possible, but let's use location state
    navigate('/study', { state: { sentences: selected, title: '랜덤 10개 학습' } });
  };

  return (
    <div className="pb-24 min-h-screen">
      <Header title="Study Buddy" showBack={false} />

      {state.loading && <LoadingOverlay />}

      <div className="px-4 mt-6">
        <Calendar 
          onChange={handleDateClick as any} 
          tileContent={tileContent}
          className="mb-8"
        />
      </div>

      <StatsDashboard sentences={state.sentences} />

      <div className="px-4">
        <button
          onClick={handleRandomStudy}
          disabled={state.sentences.length === 0}
          className="w-full bg-gradient-to-r from-blue-600 to-indigo-600 text-white py-4 rounded-2xl flex items-center justify-center gap-3 font-bold shadow-lg shadow-blue-200 active:scale-95 transition-transform disabled:opacity-50"
        >
          <Shuffle className="w-6 h-6" />
          랜덤 10개 문장 학습하기
        </button>
      </div>

      {/* FAB */}
      <button
        onClick={() => navigate('/input')}
        className="fixed bottom-6 right-6 w-16 h-16 bg-blue-600 text-white rounded-full shadow-2xl flex items-center justify-center hover:bg-blue-700 transition-colors active:scale-90 z-40"
      >
        <Plus className="w-8 h-8" />
      </button>
    </div>
  );
};

export default MainView;

import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp } from '../App';
import { Header, EmptyState } from '../components/Layout';
import { Edit2, PlayCircle, Star, Calendar } from 'lucide-react';

const ListView: React.FC = () => {
  const { type, value } = useParams<{ type: string; value: string }>();
  const { state, updateBookmarkOptimistically } = useApp();
  const navigate = useNavigate();

  const filteredSentences = state.sentences.filter(s => {
    if (type === 'all') return true;
    if (type === 'date') return s.date === value;
    if (type === 'bookmark') return s.bookmark === true;
    if (type === 'streak') return true; // Just show all if coming from streak
    return true;
  });

  const getTitle = () => {
    if (type === 'date') return value || '날짜별 목록';
    if (type === 'bookmark') return '북마크 리스트';
    if (type === 'streak') return '학습 기록';
    return '전체 문장 목록';
  };

  const handleStartStudy = () => {
    if (filteredSentences.length === 0) return;
    const shuffled = [...filteredSentences].sort(() => 0.5 - Math.random());
    navigate('/study', { state: { sentences: shuffled, title: getTitle() } });
  };

  return (
    <div className="pb-10 min-h-screen">
      <Header title={getTitle()} />

      <div className="px-4 pt-4 sticky top-[56px] bg-white z-10 pb-4 shadow-sm">
        <button
          onClick={handleStartStudy}
          disabled={filteredSentences.length === 0}
          className="w-full bg-blue-600 text-white py-3 rounded-xl flex items-center justify-center gap-2 font-bold shadow-md disabled:opacity-50"
        >
          <PlayCircle className="w-5 h-5" />
          학습 시작하기
        </button>
      </div>

      <div className="px-4 mt-6 space-y-4">
        {filteredSentences.length === 0 ? (
          <EmptyState />
        ) : (
          filteredSentences.map(s => (
            <div key={s.id} className="bg-white border border-gray-100 rounded-2xl p-4 shadow-sm flex items-start gap-4">
              <div className="flex-1">
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-[10px] font-bold text-blue-500 bg-blue-50 px-2 py-0.5 rounded uppercase tracking-tighter">
                    {s.date}
                  </span>
                  {s.bookmark && <Star className="w-3 h-3 fill-yellow-400 text-yellow-400" />}
                </div>
                <p className="text-gray-900 font-semibold mb-1 leading-tight">{s.sentence}</p>
                <p className="text-gray-500 text-sm">{s.meaning}</p>
              </div>
              <div className="flex flex-col gap-2">
                <button 
                  onClick={() => navigate(`/edit/${s.id}`)}
                  className="p-2 bg-gray-50 rounded-full text-gray-400 hover:text-blue-500 hover:bg-blue-50 transition-colors"
                >
                  <Edit2 className="w-4 h-4" />
                </button>
                <button 
                  onClick={() => updateBookmarkOptimistically(s.id)}
                  className={`p-2 rounded-full transition-colors ${s.bookmark ? 'text-yellow-500 bg-yellow-50' : 'text-gray-300 bg-gray-50'}`}
                >
                  <Star className="w-4 h-4 fill-current" />
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default ListView;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp } from '../App';
import { Header, LoadingOverlay } from '../components/Layout';
import { apiService } from '../services/apiService';
import { Trash2, Save, X } from 'lucide-react';
import { Sentence } from '../types';

const InputView: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const { state, refreshData } = useApp();
  const navigate = useNavigate();
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [formData, setFormData] = useState<Partial<Sentence>>({
    sentence: '',
    meaning: '',
    hint: '',
    referenceUrl: '',
    date: new Date().toISOString().split('T')[0],
    bookmark: false,
  });

  useEffect(() => {
    if (id) {
      const existing = state.sentences.find(s => s.id === id);
      if (existing) {
        setFormData(existing);
      }
    }
  }, [id, state.sentences]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.sentence || !formData.meaning) {
      alert("문장과 의미를 입력해주세요.");
      return;
    }

    setIsSubmitting(true);
    try {
      await apiService.upsertSentence(formData);
      await refreshData();
      navigate(-1);
    } catch (err) {
      alert("저장에 실패했습니다.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async () => {
    if (!id) return;
    if (!window.confirm("정말 삭제하시겠습니까?")) return;

    setIsSubmitting(true);
    try {
      await apiService.deleteSentence(id);
      await refreshData();
      navigate('/');
    } catch (err) {
      alert("삭제에 실패했습니다.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="pb-10 min-h-screen">
