import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { Header } from '../components/Layout';
import Flashcard from '../components/Flashcard';
import { ChevronLeft, ChevronRight, RotateCcw, Home } from 'lucide-react';
import { useApp } from '../App';
import { Sentence } from '../types';

const StudyView: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { updateBookmarkOptimistically } = useApp();

  // Get sentences from location state
  const studyList: Sentence[] = location.state?.sentences || [];
  const title: string = location.state?.title || '스터디';

  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  if (studyList.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen p-6 text-center">
        <h2 className="text-xl font-bold text-gray-800 mb-4">학습할 문장이 없습니다.</h2>
        <button 
          onClick={() => navigate('/')}
          className="bg-blue-600 text-white px-8 py-3 rounded-full font-bold shadow-lg"
        >
          홈으로 돌아가기
        </button>
      </div>
    );
  }

  const currentSentence = studyList[currentIndex];

  const handleNext = () => {
    if (currentIndex < studyList.length - 1) {
      setIsFlipped(false);
      setTimeout(() => setCurrentIndex(prev => prev + 1), 200);
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      setTimeout(() => setCurrentIndex(prev => prev - 1), 200);
    }
  };

  const handleFlip = () => setIsFlipped(!isFlipped);

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      <Header title={`${title} (${currentIndex + 1}/${studyList.length})`} />

      <div className="flex-1 flex flex-col items-center justify-center px-8 pb-32">
        <Flashcard 
          sentence={currentSentence} 
          isFlipped={isFlipped}
          onFlip={handleFlip}
          onToggleBookmark={() => updateBookmarkOptimistically(currentSentence.id)}
        />

        <div className="mt-12 flex items-center justify-between w-full max-w-[280px]">
          <button
            onClick={handlePrev}
            disabled={currentIndex === 0}
            className="w-14 h-14 bg-white rounded-full shadow-md flex items-center justify-center text-gray-600 disabled:opacity-30 disabled:shadow-none active:scale-90 transition-transform"
          >
            <ChevronLeft className="w-8 h-8" />
          </button>

          <button
            onClick={() => setIsFlipped(!isFlipped)}
            className="w-16 h-16 bg-blue-100 text-blue-600 rounded-full shadow-md flex items-center justify-center active:scale-90 transition-transform"
          >
            <RotateCcw className={`w-8 h-8 transition-transform duration-500 ${isFlipped ? 'rotate-180' : ''}`} />
          </button>

          <button
            onClick={handleNext}
            disabled={currentIndex === studyList.length - 1}
            className="w-14 h-14 bg-white rounded-full shadow-md flex items-center justify-center text-gray-600 disabled:opacity-30 disabled:shadow-none active:scale-90 transition-transform"
          >
            <ChevronRight className="w-8 h-8" />
          </button>
        </div>
      </div>

      <div className="p-6 fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white/80 backdrop-blur-md">
        <button
          onClick={() => navigate('/')}
          className="w-full bg-gray-900 text-white py-4 rounded-2xl flex items-center justify-center gap-3 font-bold active:scale-95 transition-transform"
        >
          <Home className="w-5 h-5" />
          홈 화면으로 돌아가기
        </button>
      </div>
    </div>
  );
};

export default StudyView;

import { Sentence } from '../types';

// 사용자가 제공한 실제 구글 앱스 스크립트 Web App URL
const API_URL = "https://script.google.com/macros/s/AKfycbyEsAWKJ4S4gsPiZPWqnpTqovAn6KR_yXcCnkQ_5UgZEqKR-yQB0w2T3jQkWBaVMiX3/exec";

export const apiService = {
  /**
   * 전체 문장 데이터를 조회합니다.
   */
  async fetchSentences(): Promise<Sentence[]> {
    try {
      const response = await fetch(API_URL, {
        method: 'GET',
        redirect: 'follow'
      });
      if (!response.ok) throw new Error("데이터를 불러오는데 실패했습니다.");
      return await response.json();
    } catch (err) {
      console.error("API Fetch Error:", err);
      // 에러 발생 시에만 폴백으로 빈 배열 혹은 예시 데이터를 반환할 수 있습니다.
      return []; 
    }
  },

  /**
   * 문장을 추가하거나 수정(Upsert)합니다.
   */
  async upsertSentence(sentence: Partial<Sentence>): Promise<any> {
    return this.post({ action: 'upsert', data: sentence });
  },

  /**
   * ID를 기준으로 문장을 삭제합니다.
   */
  async deleteSentence(id: string): Promise<any> {
    return this.post({ action: 'delete', id });
  },

  /**
   * 북마크 상태를 반전시킵니다.
   */
  async toggleBookmark(id: string): Promise<any> {
    return this.post({ action: 'toggleBookmark', id });
  },

  /**
   * 구글 앱스 스크립트 POST 통신을 위한 공통 메서드입니다.
   */
  async post(body: any): Promise<any> {
    try {
      // GAS Web App은 보안 정책상 no-cors 모드에서 본문 전송 시 
      // Content-Type을 text/plain으로 설정해야 데이터가 정상적으로 전달됩니다.
      await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors',
        cache: 'no-cache',
        redirect: 'follow',
        headers: {
          'Content-Type': 'text/plain',
        },
        body: JSON.stringify(body),
      });
      // no-cors 모드에서는 응답 본문을 읽을 수 없으나, 요청 성공으로 간주합니다.
      return { success: true };
    } catch (err) {
      console.error("API POST Error:", err);
      throw err;
    }
  },

  /**
   * 개발/테스트용 예시 데이터입니다.
   */
  getMockData(): Sentence[] {
    return [
      {
        id: 'mock-1',
        date: new Date().toISOString().split('T')[0],
        sentence: 'The journey of a thousand miles begins with a single step.',
        meaning: '천 리 길도 한 걸음부터.',
        hint: 'Starts with "The journey"',
        referenceUrl: 'https://example.com',
        bookmark: true,
        createdAt: new Date().toISOString()
      },
      {
        id: 'mock-2',
        date: new Date(Date.now() - 86400000).toISOString().split('T')[0],
        sentence: 'Practice makes perfect.',
        meaning: '연습이 완벽을 만든다.',
        hint: 'Consistency is key',
        referenceUrl: '',
        bookmark: false,
        createdAt: new Date().toISOString()
      }
    ];
  }
};

