import React, { useState, useEffect, createContext, useContext } from 'react';
import { HashRouter, Routes, Route } from 'react-router-dom';
import { Sentence, AppState } from './types';
import { apiService } from './services/apiService';

import MainView from './views/MainView';
import ListView from './views/ListView';
import InputView from './views/InputView';
import StudyView from './views/StudyView';

interface AppContextType {
  state: AppState;
  refreshData: () => Promise<void>;
  updateBookmarkOptimistically: (id: string) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    sentences: [],
    loading: true,
    error: null,
  });

  const refreshData = async () => {
    setState(prev => ({ ...prev, loading: true }));
    try {
      const data = await apiService.fetchSentences();
      setState({ sentences: data, loading: false, error: null });
    } catch (err) {
      setState(prev => ({ ...prev, loading: false, error: "Failed to load data" }));
    }
  };

  const updateBookmarkOptimistically = (id: string) => {
    setState(prev => ({
      ...prev,
      sentences: prev.sentences.map(s => s.id === id ? { ...s, bookmark: !s.bookmark } : s)
    }));
    apiService.toggleBookmark(id).catch(() => {
      console.error("Failed to update bookmark on server");
    });
  };

  useEffect(() => {
    refreshData();
  }, []);

  return (
    <AppContext.Provider value={{ state, refreshData, updateBookmarkOptimistically }}>
      <HashRouter>
        <div className="min-h-screen max-w-md mx-auto bg-white shadow-xl relative overflow-x-hidden">
          <Routes>
            <Route path="/" element={<MainView />} />
            <Route path="/list/:type/:value" element={<ListView />} />
            <Route path="/input" element={<InputView />} />
            <Route path="/edit/:id" element={<InputView />} />
            <Route path="/study" element={<StudyView />} />
          </Routes>
        </div>
      </HashRouter>
    </AppContext.Provider>
  );
};

export default App;

import React from 'react';
import Calendar from 'react-calendar';
import { Plus, Shuffle } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useApp } from '../App';
import { Header, LoadingOverlay } from '../components/Layout';
import StatsDashboard from '../components/StatsDashboard';

const MainView: React.FC = () => {
  const { state } = useApp();
  const navigate = useNavigate();

  const getDaySentences = (date: Date) => {
    const offset = date.getTimezoneOffset() * 60000;
    const dateStr = new Date(date.getTime() - offset).toISOString().split('T')[0];
    return state.sentences.filter(s => s.date === dateStr);
  };

  const tileContent = ({ date, view }: { date: Date, view: string }) => {
    if (view === 'month') {
      const daySentences = getDaySentences(date);
      if (daySentences.length > 0) {
        return <div className="dot-indicator"></div>;
      }
    }
    return null;
  };

  const handleDateClick = (date: Date) => {
    const offset = date.getTimezoneOffset() * 60000;
    const dateStr = new Date(date.getTime() - offset).toISOString().split('T')[0];
    navigate(`/list/date/${dateStr}`);
  };

  const handleRandomStudy = () => {
    if (state.sentences.length === 0) return;
    const shuffled = [...state.sentences].sort(() => 0.5 - Math.random());
    const selected = shuffled.slice(0, 10);
    navigate('/study', { state: { sentences: selected, title: '랜덤 10개 학습' } });
  };

  return (
    <div className="pb-24 min-h-screen">
      <Header title="Study Buddy" showBack={false} />

      {state.loading && <LoadingOverlay />}

      <div className="px-4 mt-6">
        <Calendar 
          onChange={handleDateClick as any} 
          tileContent={tileContent}
          className="mb-8"
        />
      </div>

      <StatsDashboard sentences={state.sentences} />

      <div className="px-4">
        <button
          onClick={handleRandomStudy}
          disabled={state.sentences.length === 0}
          className="w-full bg-gradient-to-r from-blue-600 to-indigo-600 text-white py-4 rounded-2xl flex items-center justify-center gap-3 font-bold shadow-lg shadow-blue-200 active:scale-95 transition-transform disabled:opacity-50"
        >
          <Shuffle className="w-6 h-6" />
          랜덤 10개 문장 학습하기
        </button>
      </div>

      <button
        onClick={() => navigate('/input')}
        className="fixed bottom-6 right-6 w-16 h-16 bg-blue-600 text-white rounded-full shadow-2xl flex items-center justify-center hover:bg-blue-700 transition-colors active:scale-90 z-40"
      >
        <Plus className="w-8 h-8" />
      </button>
    </div>
  );
};

export default MainView;

import React from 'react';
