        </button>
      </div>

      <div className="px-4 mt-6">
        {filteredSentences.length === 0 ? (
          <EmptyState />
        ) : (
          type === 'streak' || type === 'all' ? (
            // Grouped view for streak and all
            <div className="space-y-8">
              {sortedDates.map(date => (
                <div key={date} className="space-y-3">
