import React, { useState } from 'react';
import Calendar from 'react-calendar';
import { Plus, Shuffle, CalendarDays } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useApp } from '../App';
import { Header, LoadingOverlay } from '../components/Layout';
import StatsDashboard from '../components/StatsDashboard';

const MainView: React.FC = () => {
  const { state } = useApp();
  const navigate = useNavigate();

  const [value, setValue] = useState(new Date());
  const [activeStartDate, setActiveStartDate] = useState<Date | undefined>(undefined);

  const formatDate = (date: Date) => {
    // 한국 시간대 기준 YYYY-MM-DD 보장
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const getDaySentences = (date: Date) => {
    const targetDateStr = formatDate(date);
    return state.sentences.filter(s => {
      const sDateStr = s.date && typeof s.date === 'string' ? s.date.substring(0, 10) : '';
      return sDateStr === targetDateStr;
    });
  };

  const tileContent = ({ date, view }: { date: Date, view: string }) => {
    if (view === 'month') {
      const daySentences = getDaySentences(date);
      if (daySentences.length > 0) {
        return <div className="dot-indicator"></div>;
      }
    }
    return null;
  };

  const formatDay = (_locale: string | undefined, date: Date) => {
    return date.getDate().toString();
  };

  const handleDateClick = (date: Date) => {
    setValue(date);
    const dateStr = formatDate(date);
    navigate(`/list/date/${dateStr}`);
  };

  const goToToday = () => {
    const today = new Date();
    setValue(today);
    setActiveStartDate(today);
    setTimeout(() => setActiveStartDate(undefined), 100);
  };

  const handleRandomStudy = () => {
    if (state.sentences.length === 0) return;
    const shuffled = [...state.sentences].sort(() => 0.5 - Math.random());
    const selected = shuffled.slice(0, 10);
    navigate('/study', { state: { sentences: selected, title: '랜덤 10개 학습' } });
  };

  return (
    <div className="pb-24 min-h-screen bg-slate-50">
      <Header title="Study Buddy" showBack={false} />

      {state.loading && <LoadingOverlay />}

      <div className="px-5 mt-6 relative">
        <div className="flex justify-between items-center mb-2 px-1">
          <h2 className="text-sm font-bold text-slate-400 flex items-center gap-1.5">
            <CalendarDays className="w-4 h-4" />
            Learning Calendar
          </h2>
          <button
            onClick={goToToday}
            className="text-xs font-bold text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-full hover:bg-indigo-100 transition-colors active:scale-95"
          >
            Today
          </button>
        </div>

        <Calendar 
          onChange={handleDateClick as any} 
          value={value}
          activeStartDate={activeStartDate}
          onActiveStartDateChange={({ activeStartDate }) => setActiveStartDate(activeStartDate as Date)}
          tileContent={tileContent}
          formatDay={formatDay}
          className="mb-8"
          next2Label={null}
          prev2Label={null}
        />
      </div>

      <div className="mt-2">
        <StatsDashboard sentences={state.sentences} />
      </div>

      <div className="px-5 mt-4">
        <button
          onClick={handleRandomStudy}
          disabled={state.sentences.length === 0}
          className="w-full bg-indigo-600 text-white py-4.5 rounded-2xl flex items-center justify-center gap-3 font-bold shadow-xl shadow-indigo-100 hover:bg-indigo-700 active:scale-[0.98] transition-all disabled:opacity-50 disabled:shadow-none"
        >
          <Shuffle className="w-5 h-5" />
          랜덤 10개 문장 학습하기
        </button>
      </div>

      <button
        onClick={() => navigate('/input')}
        className="fixed bottom-8 right-6 w-16 h-16 bg-indigo-600 text-white rounded-full shadow-2xl flex items-center justify-center hover:bg-indigo-700 transition-all active:scale-90 z-40"
      >
        <Plus className="w-9 h-9" />
      </button>
    </div>
  );
};

export default MainView;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp } from '../App';
import { Header, LoadingOverlay } from '../components/Layout';
import { apiService } from '../services/apiService';
import { Trash2, Save } from 'lucide-react';
import { Sentence } from '../types';

const InputView: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const { state, refreshData } = useApp();
  const navigate = useNavigate();
  const [isSubmitting, setIsSubmitting] = useState(false);

  const getTodayLocal = () => {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const [formData, setFormData] = useState<Partial<Sentence>>({
    sentence: '',
    meaning: '',
    hint: '',
    referenceUrl: '',
    date: getTodayLocal(),
    bookmark: false,
  });

  useEffect(() => {
    if (id) {
      const existing = state.sentences.find(s => s.id === id);
      if (existing) {
        const formattedDate = existing.date && typeof existing.date === 'string' 
          ? existing.date.substring(0, 10) 
          : existing.date;
        setFormData({ ...existing, date: formattedDate });
      }
    }
  }, [id, state.sentences]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.sentence || !formData.meaning) {
      alert("문장과 의미를 입력해주세요.");
      return;
    }

    setIsSubmitting(true);
    try {
      await apiService.upsertSentence(formData);
      await refreshData();
      navigate(-1);
    } catch (err) {
      alert("저장에 실패했습니다.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async () => {
    if (!id) return;
    if (!window.confirm("정말 삭제하시겠습니까?")) return;

    setIsSubmitting(true);
    try {
      await apiService.deleteSentence(id);
      await refreshData();
      navigate('/');
    } catch (err) {
      alert("삭제에 실패했습니다.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="pb-10 min-h-screen">
      <Header title={id ? "문장 수정" : "새 문장 입력"} />

      {isSubmitting && <LoadingOverlay />}

      <form onSubmit={handleSubmit} className="px-6 py-8 space-y-6">
        <div className="space-y-2">
          <label className="text-sm font-bold text-gray-700">영어 문장</label>
          <textarea
            required
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 focus:border-transparent min-h-[120px] outline-none transition-all"
            placeholder="영어 문장을 입력하세요"
            value={formData.sentence}
            onChange={e => setFormData({ ...formData, sentence: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-bold text-gray-700">의미 (한국어)</label>
          <input
            required
            type="text"
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            placeholder="의미를 입력하세요"
            value={formData.meaning}
            onChange={e => setFormData({ ...formData, meaning: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-bold text-gray-700">힌트 (선택)</label>
          <input
            type="text"
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            placeholder="학습에 도움이 될 힌트를 적으세요"
            value={formData.hint}
            onChange={e => setFormData({ ...formData, hint: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-bold text-gray-700">참고 URL (선택)</label>
          <input
            type="url"
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            placeholder="https://..."
            value={formData.referenceUrl}
            onChange={e => setFormData({ ...formData, referenceUrl: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-bold text-gray-700">날짜</label>
          <input
            type="date"
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            value={formData.date}
            onChange={e => setFormData({ ...formData, date: e.target.value })}
          />
        </div>

        <div className="flex gap-4 pt-6">
          {id && (
            <button
              type="button"
              onClick={handleDelete}
              className="flex-1 flex items-center justify-center gap-2 bg-red-50 text-red-600 py-4 rounded-2xl font-bold hover:bg-red-100 transition-colors"
            >
              <Trash2 className="w-5 h-5" />
              삭제
            </button>
          )}
          <button
            type="submit"
            className="flex-[2] flex items-center justify-center gap-2 bg-blue-600 text-white py-4 rounded-2xl font-bold hover:bg-blue-700 shadow-lg shadow-blue-100 transition-all active:scale-95"
          >
            <Save className="w-5 h-5" />
            저장하기
          </button>
        </div>
      </form>
    </div>
  );
};

export default InputView;

import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp } from '../App';
import { Header, EmptyState } from '../components/Layout';
import { Edit2, PlayCircle, Star, Calendar, Play } from 'lucide-react';
import { Sentence } from '../types';

const ListView: React.FC = () => {
  const { type, value } = useParams<{ type: string; value: string }>();
  const { state, updateBookmarkOptimistically } = useApp();
  const navigate = useNavigate();

  // 날짜 문자열을 YYYY-MM-DD 형식으로 안전하게 변환하는 함수
  const formatDateString = (dateStr: string) => {
    if (!dateStr) return '날짜 없음';
    return dateStr.substring(0, 10);
  };

  const filteredSentences = state.sentences.filter(s => {
    if (type === 'all') return true;
    if (type === 'date') return formatDateString(s.date) === value;
    if (type === 'bookmark') return s.bookmark === true;
    if (type === 'streak') return true; 
    return true;
  });

  const getTitle = () => {
    if (type === 'date') return value || '날짜별 목록';
    if (type === 'bookmark') return '북마크 리스트';
    if (type === 'streak') return '학습 기록';
    return '전체 문장 목록';
  };

  const handleStartStudy = (targetSentences: Sentence[] = filteredSentences, customTitle?: string) => {
    if (targetSentences.length === 0) return;
    const shuffled = [...targetSentences].sort(() => 0.5 - Math.random());
    navigate('/study', { state: { sentences: shuffled, title: customTitle || getTitle() } });
  };

  // 그룹화 및 정렬
  const groupedByDate = filteredSentences.reduce((acc, sentence) => {
    const date = formatDateString(sentence.date);
    if (!acc[date]) {
      acc[date] = [];
    }
    acc[date].push(sentence);
    return acc;
  }, {} as Record<string, Sentence[]>);

  // 날짜 내림차순 정렬 (최신순)
  const sortedDates = Object.keys(groupedByDate).sort((a, b) => b.localeCompare(a));

  const renderSentenceCard = (s: Sentence) => (
    <div key={s.id} className="bg-white border border-gray-100 rounded-2xl p-4 shadow-sm flex items-start gap-4 hover:border-blue-100 transition-colors">
      <div className="flex-1">
        <div className="flex items-center gap-2 mb-1">
          <span className="text-[10px] font-bold text-blue-600 bg-blue-50 px-2 py-0.5 rounded tracking-tight">
            {formatDateString(s.date)}
          </span>
          {s.bookmark && <Star className="w-3 h-3 fill-yellow-400 text-yellow-400" />}
        </div>
        <p className="text-gray-900 font-semibold mb-1 leading-tight">{s.sentence}</p>
        <p className="text-gray-500 text-sm">{s.meaning}</p>
      </div>
      <div className="flex flex-col gap-2">
        <button 
          onClick={() => navigate(`/edit/${s.id}`)}
          className="p-2 bg-gray-50 rounded-full text-gray-400 hover:text-blue-500 hover:bg-blue-50 transition-colors"
        >
          <Edit2 className="w-4 h-4" />
        </button>
        <button 
          onClick={() => updateBookmarkOptimistically(s.id)}
          className={`p-2 rounded-full transition-colors ${s.bookmark ? 'text-yellow-500 bg-yellow-50' : 'text-gray-300 bg-gray-50'}`}
        >
          <Star className="w-4 h-4 fill-current" />
        </button>
      </div>
    </div>
  );

  return (
    <div className="pb-10 min-h-screen">
      <Header title={getTitle()} />

      <div className="px-4 pt-4 sticky top-[56px] bg-white/90 backdrop-blur-md z-20 pb-4 shadow-sm border-b border-gray-50">
        <button
          onClick={() => handleStartStudy()}
          disabled={filteredSentences.length === 0}
          className="w-full bg-blue-600 text-white py-3.5 rounded-xl flex items-center justify-center gap-2 font-bold shadow-lg shadow-blue-100 disabled:opacity-50 active:scale-95 transition-all"
        >
          <PlayCircle className="w-5 h-5" />
          전체 리스트 학습하기
        </button>
      </div>

      <div className="px-4 mt-6">
        {filteredSentences.length === 0 ? (
          <EmptyState />
        ) : (
          type === 'streak' || type === 'all' ? (
            <div className="space-y-10">
              {sortedDates.map(date => (
                <div key={date} className="space-y-4">
                  <div 
                    className="flex items-center gap-3 px-1 group cursor-pointer"
                    onClick={() => handleStartStudy(groupedByDate[date], `${date} 학습`)}
                  >
                    <div className="bg-slate-800 p-1.5 rounded-lg shadow-sm group-hover:bg-blue-600 transition-colors">
                      <Calendar className="w-3.5 h-3.5 text-white" />
                    </div>
                    <div className="flex flex-col">
                      <h3 className="text-base font-black text-slate-800 tracking-tight leading-none mb-1 group-hover:text-blue-600 transition-colors">{date}</h3>
                      <span className="text-[10px] font-bold text-slate-400">
                        {groupedByDate[date].length} 문장
                      </span>
                    </div>
                    <div className="h-[1px] flex-1 bg-gradient-to-r from-slate-200 to-transparent"></div>
                    <button
                      className="flex items-center gap-1 bg-blue-50 text-blue-600 px-3 py-1.5 rounded-full text-xs font-bold hover:bg-blue-600 hover:text-white transition-all active:scale-95"
                    >
                      <Play className="w-3 h-3 fill-current" />
                      학습
                    </button>
                  </div>
                  <div className="space-y-3">
                    {groupedByDate[date].map(s => renderSentenceCard(s))}
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="space-y-3">
              {filteredSentences.map(s => renderSentenceCard(s))}
            </div>
          )
        )}
      </div>
    </div>
  );
};

export default ListView;

/**
 * INSTRUCTIONS:
 * 1. Open a Google Sheet.
 * 2. Go to Extensions > Apps Script.
 * 3. Replace the code with this snippet.
 * 4. Click 'Deploy' > 'New Deployment' > 'Web App'.
 * 5. Set 'Who has access' to 'Anyone'.
 * 6. Copy the URL and paste it into `services/apiService.ts` in your React app.
 */

const SHEET_NAME = "Sentences";

function setup() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_NAME);
  if (!sheet) {
    sheet = ss.insertSheet(SHEET_NAME);
    sheet.appendRow(["id", "date", "sentence", "meaning", "hint", "referenceUrl", "bookmark", "createdAt"]);
  }
}

function doGet(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_NAME);
  const data = sheet.getDataRange().getValues();
  const headers = data[0];
  const rows = data.slice(1);

  const jsonData = rows.map(row => {
    let obj = {};
    headers.forEach((header, i) => {
      let value = row[i];

      // 날짜 객체인 경우 한국 시간(KST) 기준으로 문자열 변환
      if (value instanceof Date) {
        if (header === 'date') {
          // 'date' 컬럼은 YYYY-MM-DD 형식으로 고정
          value = Utilities.formatDate(value, "Asia/Seoul", "yyyy-MM-dd");
        } else {
          // createdAt 등 기타 날짜는 ISO 형식 문자열로 변환
          value = value.toISOString();
        }
      }

      obj[header] = value;
    });

    // 불리언 타입 보정
    obj.bookmark = (obj.bookmark === true || obj.bookmark === "true" || obj.bookmark === "TRUE");
    return obj;
  });

  return ContentService.createTextOutput(JSON.stringify(jsonData))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  const body = JSON.parse(e.postData.contents);
  const action = body.action;
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_NAME);
  const data = sheet.getDataRange().getValues();
  const headers = data[0];

  if (action === "upsert") {
    const item = body.data;
    let rowIndex = -1;

    if (item.id) {
      for (let i = 1; i < data.length; i++) {
        if (data[i][0] == item.id) {
          rowIndex = i + 1;
          break;
        }
      }
    }

    const id = item.id || Utilities.getUuid();
    // 저장 시에도 명시적으로 날짜 포맷팅 고려
    const rowData = [
      id,
      item.date || Utilities.formatDate(new Date(), "Asia/Seoul", "yyyy-MM-dd"),
      item.sentence || "",
      item.meaning || "",
      item.hint || "",
      item.referenceUrl || "",
      item.bookmark || false,
      item.createdAt || new Date().toISOString()
    ];

    if (rowIndex > 0) {
      sheet.getRange(rowIndex, 1, 1, rowData.length).setValues([rowData]);
    } else {
      sheet.appendRow(rowData);
    }
    return ContentService.createTextOutput(JSON.stringify({ success: true, id: id }))
      .setMimeType(ContentService.MimeType.JSON);

  } else if (action === "delete") {
    const id = body.id;
    for (let i = 1; i < data.length; i++) {
      if (data[i][0] == id) {
        sheet.deleteRow(i + 1);
        break;
      }
    }
    return ContentService.createTextOutput(JSON.stringify({ success: true }))
      .setMimeType(ContentService.MimeType.JSON);

  } else if (action === "toggleBookmark") {
    const id = body.id;
    let currentVal = false;
    for (let i = 1; i < data.length; i++) {
      if (data[i][0] == id) {
        currentVal = (data[i][6] === true || data[i][6] === "true" || data[i][6] === "TRUE");
        sheet.getRange(i + 1, 7).setValue(!currentVal);
        break;
      }
    }
    return ContentService.createTextOutput(JSON.stringify({ success: true, bookmark: !currentVal }))
      .setMimeType(ContentService.MimeType.JSON);
  }

  return ContentService.createTextOutput(JSON.stringify({ success: false, error: "Invalid action" }))
    .setMimeType(ContentService.MimeType.JSON);
}

import React, { useState } from 'react';
import Calendar from 'react-calendar';
import { Plus, Shuffle, CalendarDays } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useApp } from '../App';
import { Header, LoadingOverlay } from '../components/Layout';
import StatsDashboard from '../components/StatsDashboard';

const MainView: React.FC = () => {
  const { state } = useApp();
  const navigate = useNavigate();

  const [value, setValue] = useState(new Date());
  const [activeStartDate, setActiveStartDate] = useState<Date | undefined>(undefined);

  const formatDate = (date: Date) => {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const getDaySentences = (date: Date) => {
    const targetDateStr = formatDate(date);
    return state.sentences.filter(s => {
      // s.date가 문자열임을 보장하고 날짜 부분만 비교
      const sDateStr = String(s.date || '').substring(0, 10);
      return sDateStr === targetDateStr;
    });
  };

  const tileContent = ({ date, view }: { date: Date, view: string }) => {
