        let value = row[i];
        if (header === 'bookmark') {
          obj[header] = (value === "true" || value === "TRUE" || value === "1");
        } else {
          obj[header] = value;
        }
      });
      return obj;
    });

    return createJsonResponse(jsonData);
  } catch (err) {
    return createJsonResponse({ error: err.toString() });
  }
}

function createJsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  try {
    const body = JSON.parse(e.postData.contents);
    const action = body.action;
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = ss.getSheetByName(SHEET_NAME);
    const range = sheet.getDataRange();
    const data = range.getValues();
    const headers = data[0];

    if (action === "upsert") {
      const item = body.data;
      let rowIndex = -1;

      if (item.id) {
        for (let i = 1; i < data.length; i++) {
          if (data[i][0] == item.id) {
            rowIndex = i + 1;
            break;
          }
        }
      }

      const id = item.id || Utilities.getUuid();
      const rowData = [
        id,
        item.date,
        item.sentence || "",
        item.meaning || "",
        item.hint || "",
        item.referenceUrl || "",
        item.bookmark || false,
        item.createdAt || new Date().toISOString()
      ];

      if (rowIndex > 0) {
        sheet.getRange(rowIndex, 1, 1, rowData.length).setValues([rowData]);
      } else {
        sheet.appendRow(rowData);
      }
      sheet.getRange(sheet.getLastRow(), 2).setNumberFormat("@");
      return createJsonResponse({ success: true, id: id });

    } else if (action === "delete") {
      const id = body.id;
      for (let i = 1; i < data.length; i++) {
        if (data[i][0] == id) {
          sheet.deleteRow(i + 1);
          break;
        }
      }
      return createJsonResponse({ success: true });

    } else if (action === "toggleBookmark") {
      const id = body.id;
      let currentVal = false;
      for (let i = 1; i < data.length; i++) {
        if (data[i][0] == id) {
          currentVal = (data[i][6] === true || data[i][6] === "true" || data[i][6] === "TRUE");
          sheet.getRange(i + 1, 7).setValue(!currentVal);
          break;
        }
      }
      return createJsonResponse({ success: true, bookmark: !currentVal });
    }
  } catch (err) {
    return createJsonResponse({ success: false, error: err.toString() });
  }
}

