  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_NAME);
  if (!sheet) return createJsonResponse([]);

  // getDisplayValues()를 사용하면 시트에 적힌 문자열 그대로(YYYY-MM-DD 등) 가져옵니다.
  const data = sheet.getDataRange().getDisplayValues();
  if (data.length < 2) return createJsonResponse([]);

  const headers = data[0];
  const rows = data.slice(1);

  const jsonData = rows.map(row => {
    let obj = {};
    headers.forEach((header, i) => {
      obj[header] = row[i];
    });
    // 북마크 타입 보정 (문자열 "true" 대응)
    obj.bookmark = (obj.bookmark === true || obj.bookmark === "true" || obj.bookmark === "TRUE" || obj.bookmark === "1");
    return obj;
  });

  return createJsonResponse(jsonData);
}

function createJsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  try {
    const body = JSON.parse(e.postData.contents);
    const action = body.action;
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = ss.getSheetByName(SHEET_NAME);
    // 쓰기 작업 시에도 기존 ID 매칭을 위해 디스플레이 값을 참조합니다.
    const data = sheet.getDataRange().getDisplayValues();

    if (action === "upsert") {
      const item = body.data;
      let rowIndex = -1;

      if (item.id) {
        for (let i = 1; i < data.length; i++) {
          if (data[i][0] == item.id) {
            rowIndex = i + 1;
            break;
          }
        }
      }

      const id = item.id || Utilities.getUuid();
      const rowData = [
        id,
        item.date || new Date().toISOString().split('T')[0],
        item.sentence || "",
        item.meaning || "",
        item.hint || "",
        item.referenceUrl || "",
        item.bookmark || false,
        item.createdAt || new Date().toISOString()
      ];

      if (rowIndex > 0) {
        sheet.getRange(rowIndex, 1, 1, rowData.length).setValues([rowData]);
      } else {
        sheet.appendRow(rowData);
      }

      // 날짜 컬럼(B) 서식을 텍스트로 강제하여 자동 변환 방지
      sheet.getRange(sheet.getLastRow(), 2).setNumberFormat("@");

      return createJsonResponse({ success: true, id: id });

    } else if (action === "delete") {
      const id = body.id;
      for (let i = 1; i < data.length; i++) {
        if (data[i][0] == id) {
          sheet.deleteRow(i + 1);
          break;
        }
      }
      return createJsonResponse({ success: true });

    } else if (action === "toggleBookmark") {
      const id = body.id;
      let currentVal = false;
      for (let i = 1; i < data.length; i++) {
        if (data[i][0] == id) {
          currentVal = (data[i][6] === true || data[i][6] === "true" || data[i][6] === "TRUE" || data[i][6] === "1");
          sheet.getRange(i + 1, 7).setValue(!currentVal);
          break;
        }
      }
      return createJsonResponse({ success: true, bookmark: !currentVal });
    }
  } catch (err) {
    return createJsonResponse({ success: false, error: err.toString() });
  }
}

