import * as ReactRouterDOM from 'react-router-dom';
import { useApp } from '../App';
import { Header, LoadingOverlay } from '../components/Layout';
import { apiService } from '../services/apiService';
import { Trash2, Save, Sparkles } from 'lucide-react';
import { Sentence } from '../types';
// Import Gemini API
import { GoogleGenAI } from "@google/genai";

const { useParams, useNavigate } = ReactRouterDOM;

const InputView: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const { state, refreshData } = useApp();
  const navigate = useNavigate();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingAI, setIsGeneratingAI] = useState(false);

  const getTodayLocal = () => {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const [formData, setFormData] = useState<Partial<Sentence>>({
    sentence: '',
    meaning: '',
    hint: '',
    referenceUrl: '',
    date: getTodayLocal(),
    bookmark: false,
  });

  useEffect(() => {
    if (id) {
      const existing = state.sentences.find(s => s.id === id);
      if (existing) {
        const formattedDate = existing.date && typeof existing.date === 'string' 
          ? existing.date.substring(0, 10) 
          : existing.date;
        setFormData({ ...existing, date: formattedDate });
      }
    }
  }, [id, state.sentences]);

  // Fix: Add Gemini AI recommendation feature
  const handleAIGenerate = async () => {
    setIsGeneratingAI(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: '일상생활에서 자주 쓰이는 유용한 영어 학습용 문장 한 개를 골라줘. 문장은 English, 의미는 Korean으로 작성해줘. JSON 형식으로만 응답해줘: { "sentence": "...", "meaning": "...", "hint": "..." }',
        config: { 
          responseMimeType: "application/json"
        }
      });

      const text = response.text;
      if (text) {
        const data = JSON.parse(text.trim());
        setFormData(prev => ({
          ...prev,
          sentence: data.sentence || '',
          meaning: data.meaning || '',
          hint: data.hint || ''
        }));
      }
    } catch (err) {
      console.error("AI Generation Error:", err);
      alert("AI 추천 문장을 가져오는데 실패했습니다.");
    } finally {
      setIsGeneratingAI(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.sentence || !formData.meaning) {
      alert("문장과 의미를 입력해주세요.");
      return;
    }

    setIsSubmitting(true);
    try {
      await apiService.upsertSentence(formData);
      await refreshData();
      navigate(-1);
    } catch (err) {
      alert("저장에 실패했습니다.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async () => {
    if (!id) return;
    if (!window.confirm("정말 삭제하시겠습니까?")) return;

    setIsSubmitting(true);
    try {
      await apiService.deleteSentence(id);
      await refreshData();
      navigate('/');
    } catch (err) {
      alert("삭제에 실패했습니다.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="pb-10 min-h-screen">
      <Header title={id ? "문장 수정" : "새 문장 입력"} />

      {(isSubmitting || isGeneratingAI) && <LoadingOverlay />}

      <form onSubmit={handleSubmit} className="px-6 py-8 space-y-6">
        <div className="space-y-2">
          <div className="flex justify-between items-center">
            <label className="text-sm font-bold text-gray-700">영어 문장</label>
            {!id && (
              <button
                type="button"
                onClick={handleAIGenerate}
                className="flex items-center gap-1.5 text-[11px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-full hover:bg-indigo-100 transition-colors active:scale-95"
              >
                <Sparkles className="w-3.5 h-3.5" />
                AI 추천 문장
              </button>
            )}
          </div>
          <textarea
            required
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 focus:border-transparent min-h-[120px] outline-none transition-all"
            placeholder="영어 문장을 입력하세요"
            value={formData.sentence}
            onChange={e => setFormData({ ...formData, sentence: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-bold text-gray-700">의미 (한국어)</label>
          <input
            required
            type="text"
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            placeholder="의미를 입력하세요"
            value={formData.meaning}
            onChange={e => setFormData({ ...formData, meaning: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-bold text-gray-700">힌트 (선택)</label>
          <input
            type="text"
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            placeholder="학습에 도움이 될 힌트를 적으세요"
            value={formData.hint}
            onChange={e => setFormData({ ...formData, hint: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-bold text-gray-700">참고 URL (선택)</label>
          <input
            type="url"
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            placeholder="https://..."
            value={formData.referenceUrl}
            onChange={e => setFormData({ ...formData, referenceUrl: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-bold text-gray-700">날짜</label>
          <input
            type="date"
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            value={formData.date}
            onChange={e => setFormData({ ...formData, date: e.target.value })}
          />
        </div>

        <div className="flex gap-4 pt-6">
          {id && (
            <button
              type="button"
              onClick={handleDelete}
              className="flex-1 flex items-center justify-center gap-2 bg-red-50 text-red-600 py-4 rounded-2xl font-bold hover:bg-red-100 transition-colors"
            >
              <Trash2 className="w-5 h-5" />
              삭제
            </button>
          )}
          <button
            type="submit"
            className="flex-[2] flex items-center justify-center gap-2 bg-blue-600 text-white py-4 rounded-2xl font-bold hover:bg-blue-700 shadow-lg shadow-blue-100 transition-all active:scale-95"
          >
            <Save className="w-5 h-5" />
            저장하기
          </button>
        </div>
      </form>
    </div>
  );
};

export default InputView;

import React, { useState } from 'react';
// Fix: Use namespace import for react-router-dom
import * as ReactRouterDOM from 'react-router-dom';
import { Header } from '../components/Layout';
import Flashcard from '../components/Flashcard';
import { ChevronLeft, ChevronRight, Star } from 'lucide-react';
import { useApp } from '../App';
import { Sentence } from '../types';

const { useLocation, useNavigate } = ReactRouterDOM;

const StudyView: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { updateBookmarkOptimistically } = useApp();

  const studyList: Sentence[] = (location.state as any)?.sentences || [];
  const title: string = (location.state as any)?.title || '스터디';

  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  if (studyList.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen p-6 text-center bg-slate-50">
        <h2 className="text-xl font-bold text-slate-800 mb-4">학습할 문장이 없습니다.</h2>
        <button 
          onClick={() => navigate('/')}
          className="bg-indigo-600 text-white px-8 py-3 rounded-full font-bold shadow-lg active:scale-95 transition-transform"
        >
          홈으로 돌아가기
        </button>
      </div>
    );
  }

  const currentSentence = studyList[currentIndex];

  const handleNext = () => {
    if (currentIndex < studyList.length - 1) {
      setIsFlipped(false);
      setTimeout(() => setCurrentIndex(prev => prev + 1), 150);
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      setTimeout(() => setCurrentIndex(prev => prev - 1), 150);
    }
  };

  const handleFlip = () => setIsFlipped(!isFlipped);

  const toggleBookmark = () => {
    updateBookmarkOptimistically(currentSentence.id);
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header title={`${title} (${currentIndex + 1}/${studyList.length})`} />

      <div className="flex-1 flex flex-col items-center justify-center px-6 py-10">
        <Flashcard 
          sentence={currentSentence} 
          isFlipped={isFlipped}
          onFlip={handleFlip}
          onToggleBookmark={toggleBookmark}
        />

        <div className="mt-10 flex items-center justify-between w-full max-w-[280px]">
          <button
            onClick={handlePrev}
            disabled={currentIndex === 0}
            className="w-14 h-14 bg-white rounded-full shadow-md flex items-center justify-center text-slate-600 disabled:opacity-30 disabled:shadow-none active:scale-90 transition-all border border-slate-100"
          >
            <ChevronLeft className="w-8 h-8" />
          </button>

          <button
            onClick={toggleBookmark}
            className={`w-16 h-16 rounded-full shadow-lg flex items-center justify-center active:scale-90 transition-all border-2 ${
              currentSentence.bookmark 
                ? 'bg-yellow-50 text-yellow-500 border-yellow-200' 
                : 'bg-white text-slate-300 border-slate-100'
            }`}
          >
            <Star className={`w-8 h-8 ${currentSentence.bookmark ? 'fill-current' : ''}`} />
          </button>

          <button
            onClick={handleNext}
            disabled={currentIndex === studyList.length - 1}
            className="w-14 h-14 bg-white rounded-full shadow-md flex items-center justify-center text-slate-600 disabled:opacity-30 disabled:shadow-none active:scale-90 transition-all border border-slate-100"
          >
            <ChevronRight className="w-8 h-8" />
          </button>
        </div>
      </div>
    </div>
  );
};

export default StudyView;

