import React, { useState, useMemo, useRef, useEffect } from 'react';
import * as ReactRouterDOM from 'react-router-dom';
import { Header } from '../components/Layout';
import Flashcard from '../components/Flashcard';
import { ChevronLeft, ChevronRight, Star, Check, RotateCcw, Mic } from 'lucide-react';
import { useApp } from '../App';
import { Sentence } from '../types';
import { GoogleGenAI, Modality } from "@google/genai";

const { useLocation, useNavigate } = ReactRouterDOM;

// Audio Decoding Helpers
function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

// Web Speech API 타입 정의
interface SpeechRecognitionEvent extends Event {
  results: SpeechRecognitionResultList;
  resultIndex: number;
}

interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  lang: string;
  start: () => void;
  stop: () => void;
  onresult: (event: SpeechRecognitionEvent) => void;
  onerror: (event: any) => void;
  onend: () => void;
}

const StudyView: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { state, updateBookmarkOptimistically } = useApp();

  const touchStartX = useRef<number | null>(null);
  const touchEndX = useRef<number | null>(null);
  const minSwipeDistance = 50;

  // 음성 인식 관련 상태
  const [isRecording, setIsRecording] = useState(false);
  const [recognizedText, setRecognizedText] = useState('');
  const [accuracy, setAccuracy] = useState<number | null>(null);
  const [showResult, setShowResult] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);

  const recognitionRef = useRef<SpeechRecognition | null>(null);
  const transcriptBufferRef = useRef<string>(''); 
  const isActiveSessionRef = useRef<boolean>(false); 

  const initialSentenceIds: string[] = useMemo(() => {
    const sentences = (location.state as any)?.sentences || [];
    return sentences.map((s: Sentence) => s.id);
  }, [location.state]);

  const studyList = useMemo(() => {
    return initialSentenceIds
      .map(id => state.sentences.find(s => s.id === id))
      .filter((s): s is Sentence => !!s);
  }, [initialSentenceIds, state.sentences]);

  const title: string = (location.state as any)?.title || '스터디';

  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  // 음성 인식 시작 함수
  const startSpeechRecognition = () => {
    if (recognitionRef.current) {
      try {
        isActiveSessionRef.current = true;
        transcriptBufferRef.current = '';
        setRecognizedText('');
        setAccuracy(null);
        setShowResult(false);
        recognitionRef.current.start();
        setIsRecording(true);
      } catch (e) {
        console.warn("Recognition start failed or already running", e);
      }
    }
  };

  // 음성 인식 중지 함수
  const stopSpeechRecognition = () => {
    isActiveSessionRef.current = false;
    if (recognitionRef.current) {
      try {
        recognitionRef.current.stop();
      } catch (e) {
        // ignore
      }
      setIsRecording(false);
    }
  };

  // 제출 처리 함수
  const handleSubmit = () => {
    stopSpeechRecognition();
    calculateSimilarity(transcriptBufferRef.current, studyList[currentIndex].sentence);
  };

  // TTS 기능 (Gemini API)
  const playTTS = async (text: string) => {
    if (isSpeaking) return;
    setIsSpeaking(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `Say naturally and clearly: ${text}` }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' }, // 'Kore' is a standard high-quality voice
            },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 24000});
        const decoded = decodeBase64(base64Audio);
        const audioBuffer = await decodeAudioData(decoded, audioCtx, 24000, 1);

        const source = audioCtx.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioCtx.destination);
        source.onended = () => setIsSpeaking(false);
        source.start();
      } else {
        setIsSpeaking(false);
      }
    } catch (err) {
      console.error("TTS Error:", err);
      setIsSpeaking(false);
      // Fallback to browser TTS if Gemini fails
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'en-US';
      utterance.onend = () => setIsSpeaking(false);
      window.speechSynthesis.speak(utterance);
    }
  };

  // 문장 변경 시 초기화
  useEffect(() => {
    setRecognizedText('');
    setAccuracy(null);
    setShowResult(false);
    setIsFlipped(false);
    transcriptBufferRef.current = '';
    isActiveSessionRef.current = false;

    // 자동 녹음 타이머 제거됨. 사용자가 수동으로 시작해야 함.

    return () => {
      stopSpeechRecognition();
    };
  }, [currentIndex]);

  // Speech Recognition 초기화
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.interimResults = false;
      recognition.continuous = true;

      recognition.onresult = (event: SpeechRecognitionEvent) => {
        let finalTranscript = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript;
          }
        }
        transcriptBufferRef.current += (transcriptBufferRef.current ? ' ' : '') + finalTranscript;
      };

      recognition.onerror = (event: any) => {
        if (event.error !== 'no-speech') {
          console.error("Speech recognition error:", event.error);
        }
      };

      recognition.onend = () => {
        // 10초 세션 활성 중에 끊기면 재시작 (모바일 대응)
        if (isActiveSessionRef.current) {
          try {
            recognition.start();
          } catch (e) {}
        } else {
          setIsRecording(false);
        }
      };

      recognitionRef.current = recognition;
    }
  }, [currentIndex, studyList]);

  // 자동 제출 타이머 (수동으로 시작했을 때만 작동하도록 변경 가능하나, 일단 수동 시작 후 10초 뒤 제출로 유지)
  useEffect(() => {
    let stopTimer: number;
    if (isRecording) {
      stopTimer = window.setTimeout(() => {
        if (isActiveSessionRef.current) {
          handleSubmit();
        }
      }, 10000);
    }
    return () => clearTimeout(stopTimer);
  }, [isRecording]);

  if (studyList.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen p-6 text-center bg-slate-50">
        <h2 className="text-xl font-bold text-slate-800 mb-4">학습할 문장이 없습니다.</h2>
        <p className="text-slate-500 text-sm">상단 홈 아이콘을 눌러 돌아가주세요.</p>
      </div>
    );
  }

  const currentSentence = studyList[currentIndex];

  const calculateSimilarity = (spoken: string, target: string) => {
    const clean = (text: string) => text.toLowerCase().replace(/[.,/#!$%^&*;:{}=\-_`~()]/g, "").trim();
    const spokenWords = clean(spoken).split(/\s+/).filter(w => w.length > 0);
    const targetWords = clean(target).split(/\s+/).filter(w => w.length > 0);

    if (spokenWords.length === 0) {
      setAccuracy(0);
      setRecognizedText("");
      setShowResult(true);
      return;
    }

    let matches = 0;
    targetWords.forEach(word => {
      if (spokenWords.includes(word)) {
        matches++;
      }
    });

    const score = Math.round((matches / targetWords.length) * 100);
    setAccuracy(score);
    setRecognizedText(spoken);
    setShowResult(true);
  };

  const handleNext = () => {
    if (currentIndex < studyList.length - 1) {
      setCurrentIndex(prev => prev + 1);
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
    }
  };

  const handleFlip = () => setIsFlipped(!isFlipped);

  const onTouchStart = (e: React.TouchEvent) => {
    touchEndX.current = null;
    touchStartX.current = e.targetTouches[0].clientX;
  };

  const onTouchMove = (e: React.TouchEvent) => {
    touchEndX.current = e.targetTouches[0].clientX;
  };

  const onTouchEnd = () => {
    if (!touchStartX.current || !touchEndX.current) return;
    const distance = touchStartX.current - touchEndX.current;
    if (distance > minSwipeDistance) handleNext();
    else if (distance < -minSwipeDistance) handlePrev();
  };

  const handleMainAction = () => {
    if (showResult) {
      // 다시 시도
      startSpeechRecognition();
    } else if (isRecording) {
      // 제출
      handleSubmit();
    } else {
      // 녹음 시작
      startSpeechRecognition();
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 select-none">
      <Header title={`${title} (${currentIndex + 1}/${studyList.length})`} />

      <div 
        className="flex-1 flex flex-col items-center justify-start px-6 pt-6 pb-10 overflow-y-auto"
        onTouchStart={onTouchStart}
        onTouchMove={onTouchMove}
        onTouchEnd={onTouchEnd}
      >
        <div className="w-full max-w-sm mb-5">
          <Flashcard 
            sentence={currentSentence} 
            isFlipped={isFlipped}
            onFlip={handleFlip}
            onToggleBookmark={() => updateBookmarkOptimistically(currentSentence.id)}
            onSpeak={playTTS}
            isSpeaking={isSpeaking}
          />
        </div>

        <div className="w-full max-w-sm min-h-[110px] flex flex-col items-center justify-center bg-white rounded-3xl border border-slate-100 p-5 shadow-sm mb-6 transition-all relative overflow-hidden">
          {isRecording && (
            <div className="absolute top-3 right-4 flex items-center gap-1.5">
              <span className="w-2 h-2 bg-red-500 rounded-full animate-ping"></span>
              <span className="text-[10px] font-black text-red-500 uppercase tracking-widest">Listening</span>
            </div>
          )}

          {showResult ? (
            <div className="w-full flex flex-col items-center animate-in fade-in zoom-in duration-300">
              <p className="text-slate-400 text-[9px] font-black uppercase mb-1.5 tracking-widest">Analysis Result</p>
              <p className="text-slate-800 font-bold text-center leading-tight mb-3 italic text-lg px-2">
                "{recognizedText || "(No speech detected)"}"
              </p>
              {accuracy !== null && (
                <div className={`px-5 py-1.5 rounded-full text-xs font-black uppercase tracking-wider shadow-sm flex items-center gap-2 ${
                  accuracy >= 80 ? 'bg-emerald-500 text-white' : 'bg-orange-500 text-white'
                }`}>
                  {accuracy >= 80 ? 'Excellent!' : 'Try Again!'} {accuracy}%
                </div>
              )}
            </div>
          ) : (
            <div className="flex flex-col items-center gap-3">
              <div className="flex gap-1.5 items-end h-6">
                {[0, 1, 2, 3, 4].map(i => (
                  <div 
                    key={i} 
                    className={`w-1.5 bg-indigo-500 rounded-full ${isRecording ? 'animate-bounce' : 'opacity-20'}`} 
                    style={{animationDelay: `${i * 0.15}s`, height: `${(i+2)*4}px`}}
                  ></div>
                ))}
              </div>
              <div className="text-center">
                <p className={`${isRecording ? 'text-indigo-600' : 'text-slate-400'} text-base font-black transition-colors`}>
                  {isRecording ? '지금 바로 말씀하세요' : '버튼을 눌러 녹음을 시작하세요'}
                </p>
                {isRecording && <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest mt-0.5">10초 후 자동 제출됩니다</p>}
              </div>
            </div>
          )}
        </div>

        <div className="flex flex-col items-center gap-6 w-full max-w-sm">
          <div className="flex items-center justify-between w-full max-w-[300px]">
            <button
              onClick={handlePrev}
              disabled={currentIndex === 0 || isRecording}
              className="w-12 h-12 bg-white rounded-full shadow-sm flex items-center justify-center text-slate-400 disabled:opacity-20 active:scale-90 transition-all border border-slate-100"
            >
              <ChevronLeft className="w-6 h-6" />
            </button>

            <div className="relative">
              {isRecording && (
                <div className="absolute inset-0 bg-indigo-500 rounded-full animate-ping opacity-20 scale-125"></div>
              )}
              <button
                onClick={handleMainAction}
                className={`w-20 h-20 rounded-full shadow-xl flex flex-col items-center justify-center active:scale-95 transition-all relative z-10 border-4 border-white ${
                  showResult 
                    ? 'bg-slate-800 text-white' 
                    : isRecording ? 'bg-indigo-600 text-white' : 'bg-white text-indigo-600 border-indigo-50'
                }`}
              >
                {showResult ? (
                  <>
                    <RotateCcw className="w-7 h-7 mb-0.5" />
                    <span className="text-[8px] font-black uppercase tracking-tighter">Retry</span>
                  </>
                ) : isRecording ? (
                  <>
                    <Check className="w-8 h-8 mb-0.5" />
                    <span className="text-[8px] font-black uppercase tracking-tighter">Submit</span>
                  </>
                ) : (
                  <>
                    <Mic className="w-8 h-8 mb-0.5" />
                    <span className="text-[8px] font-black uppercase tracking-tighter">Record</span>
                  </>
                )}
              </button>
            </div>

            <button
              onClick={handleNext}
              disabled={currentIndex === studyList.length - 1 || isRecording}
              className="w-12 h-12 bg-white rounded-full shadow-sm flex items-center justify-center text-slate-400 disabled:opacity-20 active:scale-90 transition-all border border-slate-100"
            >
              <ChevronRight className="w-6 h-6" />
            </button>
          </div>

          <div className="flex items-center gap-5">
            <button
              onClick={() => updateBookmarkOptimistically(currentSentence.id)}
              className={`p-3.5 rounded-2xl transition-all border-2 ${
                currentSentence.bookmark 
                  ? 'bg-yellow-50 text-yellow-500 border-yellow-200 shadow-inner' 
                  : 'bg-white text-slate-300 border-slate-100'
              }`}
            >
              <Star className={`w-5 h-5 ${currentSentence.bookmark ? 'fill-current' : ''}`} />
            </button>

            <button
              onClick={() => {
                setRecognizedText('');
                setAccuracy(null);
                setShowResult(false);
                stopSpeechRecognition();
              }}
              className="p-3.5 bg-white rounded-2xl text-slate-400 border-2 border-slate-100 hover:text-indigo-500 hover:border-indigo-100 transition-all active:rotate-180 duration-500"
              title="Reset All"
            >
              <RotateCcw className="w-5 h-5" />
            </button>
          </div>
        </div>

        <p className="mt-8 text-[9px] font-black text-slate-300 uppercase tracking-[0.2em] text-center px-8 leading-relaxed">
          Swipe to turn page • Speak naturally • 10s Recording Window
        </p>
      </div>
    </div>
  );
};

export default StudyView;

import React, { useState, useEffect } from 'react';
// Fix: Use namespace import for react-router-dom
import * as ReactRouterDOM from 'react-router-dom';
import { useApp } from '../App';
import { Header, LoadingOverlay } from '../components/Layout';
import { apiService } from '../services/apiService';
import { Trash2, Save, Sparkles, Lock, X, AlertTriangle, Languages } from 'lucide-react';
import { Sentence } from '../types';
// Import Gemini API
import { GoogleGenAI } from "@google/genai";

const { useParams, useNavigate } = ReactRouterDOM;

const InputView: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const { state, refreshData } = useApp();
  const navigate = useNavigate();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingAI, setIsGeneratingAI] = useState(false);
  const [isTranslating, setIsTranslating] = useState(false);

  // 비밀번호 관련 상태
  const [showPasswordModal, setShowPasswordModal] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [pendingAction, setPendingAction] = useState<'save' | 'delete' | null>(null);

  const getTodayLocal = () => {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const [formData, setFormData] = useState<Partial<Sentence>>({
    sentence: '',
    meaning: '',
    hint: '',
    referenceUrl: '',
    date: getTodayLocal(),
    bookmark: false,
  });

  useEffect(() => {
    if (id) {
      const existing = state.sentences.find(s => s.id === id);
      if (existing) {
        const formattedDate = existing.date && typeof existing.date === 'string' 
          ? existing.date.substring(0, 10) 
          : existing.date;
        setFormData({ ...existing, date: formattedDate });
      }
    }
  }, [id, state.sentences]);

  // AI 추천 문장 생성
  const handleAIGenerate = async () => {
    setIsGeneratingAI(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: '일상생활에서 자주 쓰이는 유용한 영어 학습용 문장 한 개를 골라줘. 문장은 English, 의미는 Korean으로 작성해줘. JSON 형식으로만 응답해줘: { "sentence": "...", "meaning": "...", "hint": "..." }',
        config: { 
          responseMimeType: "application/json"
        }
      });

      const text = response.text;
      if (text) {
        const data = JSON.parse(text.trim());
        setFormData(prev => ({
          ...prev,
          sentence: data.sentence || '',
          meaning: data.meaning || '',
          hint: data.hint || ''
        }));
      }
    } catch (err) {
      console.error("AI Generation Error:", err);
      alert("AI 추천 문장을 가져오는데 실패했습니다.");
    } finally {
      setIsGeneratingAI(false);
    }
  };

  // 영어 문장 자동 번역 기능
  const handleTranslate = async () => {
    if (!formData.sentence || formData.sentence.trim() === '') return;

    setIsTranslating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `다음 영어 문장을 자연스러운 한국어로 번역해줘. 오직 번역된 결과만 텍스트로 반환해줘: "${formData.sentence}"`,
      });

      const translatedText = response.text;
      if (translatedText) {
        setFormData(prev => ({
          ...prev,
          meaning: translatedText.trim()
        }));
      }
    } catch (err) {
      console.error("Translation Error:", err);
      alert("번역에 실패했습니다. 다시 시도해주세요.");
    } finally {
      setIsTranslating(false);
    }
  };

  // 폼 제출(저장) 버튼 클릭 시
  const handleSubmitClick = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.sentence || !formData.meaning) {
      alert("문장과 의미를 입력해주세요.");
      return;
    }
    setPendingAction('save');
    setPasswordInput('');
    setShowPasswordModal(true);
  };

  // 삭제 버튼 클릭 시
  const handleDeleteClick = (e: React.MouseEvent) => {
    e.preventDefault();
    if (!id) return;
    setPendingAction('delete');
    setPasswordInput('');
    setShowPasswordModal(true);
  };

  // 실제 동작 실행 (비밀번호 확인 후 실행)
  const handlePasswordConfirm = async () => {
    if (passwordInput !== '1129') {
      alert("비밀번호가 틀렸습니다.");
      setPasswordInput('');
      return;
    }

    setShowPasswordModal(false);
    setIsSubmitting(true);

    try {
      if (pendingAction === 'save') {
        await apiService.upsertSentence(formData);
        await refreshData();
        navigate(-1);
      } else if (pendingAction === 'delete' && id) {
        await apiService.deleteSentence(id);
        await refreshData();
        navigate('/');
      }
    } catch (err) {
      console.error("Action Error:", err);
      alert(pendingAction === 'save' ? "저장에 실패했습니다." : "삭제에 실패했습니다.");
    } finally {
      setIsSubmitting(false);
      setPendingAction(null);
    }
  };

  return (
    <div className="pb-10 min-h-screen">
      <Header title={id ? "문장 수정" : "새 문장 입력"} />

      {(isSubmitting || isGeneratingAI || isTranslating) && <LoadingOverlay />}

      <form onSubmit={handleSubmitClick} className="px-6 py-8 space-y-6">
        <div className="space-y-2">
          <div className="flex justify-between items-center">
            <label className="text-sm font-bold text-gray-700">영어 문장</label>
            {!id && (
              <button
                type="button"
                onClick={handleAIGenerate}
                className="flex items-center gap-1.5 text-[11px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-full hover:bg-indigo-100 transition-colors active:scale-95"
              >
                <Sparkles className="w-3.5 h-3.5" />
                AI 추천 문장
              </button>
            )}
          </div>
          <textarea
            required
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 focus:border-transparent min-h-[120px] outline-none transition-all"
            placeholder="영어 문장을 입력하세요"
            value={formData.sentence}
            onChange={e => setFormData({ ...formData, sentence: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <div className="flex justify-between items-center">
            <label className="text-sm font-bold text-gray-700">의미 (한국어)</label>
            <button
              type="button"
              onClick={handleTranslate}
              disabled={!formData.sentence || isTranslating}
              className="flex items-center gap-1.5 text-[11px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-full hover:bg-indigo-100 disabled:opacity-50 disabled:cursor-not-allowed transition-all active:scale-95"
            >
              <Languages className={`w-3.5 h-3.5 ${isTranslating ? 'animate-spin' : ''}`} />
              {isTranslating ? '번역 중...' : '자동 번역'}
            </button>
          </div>
          <input
            required
            type="text"
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            placeholder="의미를 입력하세요"
            value={formData.meaning}
            onChange={e => setFormData({ ...formData, meaning: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-bold text-gray-700">힌트 (선택)</label>
          <input
            type="text"
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            placeholder="학습에 도움이 될 힌트를 적으세요"
            value={formData.hint}
            onChange={e => setFormData({ ...formData, hint: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-bold text-gray-700">참고 URL (선택)</label>
          <input
            type="url"
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            placeholder="https://..."
            value={formData.referenceUrl}
            onChange={e => setFormData({ ...formData, referenceUrl: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-bold text-gray-700">날짜</label>
          <input
            type="date"
            className="w-full border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            value={formData.date}
            onChange={e => setFormData({ ...formData, date: e.target.value })}
          />
        </div>

        <div className="flex gap-4 pt-6">
          {id && (
            <button
              type="button"
              onClick={handleDeleteClick}
              className="flex-1 flex items-center justify-center gap-2 bg-red-50 text-red-600 py-4 rounded-2xl font-bold hover:bg-red-100 transition-colors"
            >
              <Trash2 className="w-5 h-5" />
              삭제
            </button>
          )}
          <button
            type="submit"
            className="flex-[2] flex items-center justify-center gap-2 bg-blue-600 text-white py-4 rounded-2xl font-bold hover:bg-blue-700 shadow-lg shadow-blue-100 transition-all active:scale-95"
          >
            <Save className="w-5 h-5" />
            저장하기
          </button>
        </div>
      </form>

      {/* 비밀번호 입력 모달 */}
      {showPasswordModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-6">
          <div className="bg-white w-full max-w-sm rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="p-6">
              <div className="flex justify-between items-center mb-6">
                <div className={`${pendingAction === 'delete' ? 'bg-red-50' : 'bg-indigo-50'} p-2.5 rounded-xl`}>
                  {pendingAction === 'delete' ? (
                    <AlertTriangle className="w-6 h-6 text-red-600" />
                  ) : (
                    <Lock className="w-6 h-6 text-indigo-600" />
                  )}
                </div>
                <button 
                  onClick={() => setShowPasswordModal(false)}
                  className="p-2 hover:bg-slate-100 rounded-full transition-colors"
                >
                  <X className="w-5 h-5 text-slate-400" />
                </button>
              </div>

              <h3 className="text-xl font-extrabold text-slate-800 mb-2">
                {pendingAction === 'delete' ? '정말 삭제할까요?' : '비밀번호 확인'}
              </h3>
              <p className="text-slate-500 text-sm mb-6">
                {pendingAction === 'delete' ? '삭제를 진행하려면 비밀번호를 입력하세요.' : '데이터를 저장하려면 비밀번호를 입력하세요.'}
              </p>

              <input
                autoFocus
                type="password"
                inputMode="numeric"
                className={`w-full border-2 border-slate-100 bg-slate-50 rounded-2xl p-4 text-center text-2xl font-black tracking-[0.5em] outline-none transition-all mb-6 ${pendingAction === 'delete' ? 'focus:border-red-500' : 'focus:border-indigo-500'}`}
                placeholder="****"
                value={passwordInput}
                onChange={(e) => setPasswordInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') handlePasswordConfirm();
                }}
              />

              <div className="flex gap-3">
                <button
                  onClick={() => setShowPasswordModal(false)}
                  className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-all"
                >
                  취소
                </button>
                <button
                  onClick={handlePasswordConfirm}
                  className={`flex-1 py-4 text-white font-bold rounded-2xl shadow-lg active:scale-95 transition-all ${pendingAction === 'delete' ? 'bg-red-600 shadow-red-100 hover:bg-red-700' : 'bg-indigo-600 shadow-indigo-100 hover:bg-indigo-700'}`}
                >
                  확인
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default InputView;

import React from 'react';
// Fix: Use namespace import for react-router-dom
import * as ReactRouterDOM from 'react-router-dom';
import { useApp } from '../App';
import { Header, EmptyState } from '../components/Layout';
import { Edit2, PlayCircle, Star, Calendar, Play, ExternalLink, Plus } from 'lucide-react';
import { Sentence } from '../types';

const { useParams, useNavigate } = ReactRouterDOM;

const ListView: React.FC = () => {
  const { type, value } = useParams<{ type: string; value: string }>();
  const { state, updateBookmarkOptimistically } = useApp();
  const navigate = useNavigate();

  // 날짜 문자열을 YYYY-MM-DD 형식으로 안전하게 변환하는 함수
  const formatDateString = (dateStr: string) => {
    if (!dateStr) return '날짜 없음';
    return dateStr.substring(0, 10);
  };

  const filteredSentences = state.sentences.filter(s => {
    if (type === 'all') return true;
    if (type === 'date') return formatDateString(s.date) === value;
    if (type === 'bookmark') return s.bookmark === true;
    if (type === 'streak') return true; 
    return true;
  });

  const getTitle = () => {
    if (type === 'date') return value || '날짜별 목록';
    if (type === 'bookmark') return '북마크 리스트';
    if (type === 'streak') return '학습 기록';
    return '전체 문장 목록';
  };

  const handleStartStudy = (targetSentences: Sentence[] = filteredSentences, customTitle?: string) => {
    if (targetSentences.length === 0) return;
    const shuffled = [...targetSentences].sort(() => 0.5 - Math.random());
    navigate('/study', { state: { sentences: shuffled, title: customTitle || getTitle() } });
  };

  const handleCardClick = (clickedSentence: Sentence) => {
    // 현재 필터링된 전체 리스트에서 클릭된 문장을 제외한 나머지를 추출
    const others = filteredSentences.filter(s => s.id !== clickedSentence.id);
    // 나머지 문장들을 랜덤하게 섞음
    const shuffledOthers = [...others].sort(() => 0.5 - Math.random());
    // 클릭된 문장을 맨 앞에 두고 학습 리스트 구성
    const orderedList = [clickedSentence, ...shuffledOthers];

    navigate('/study', { 
      state: { 
        sentences: orderedList, 
        title: getTitle() 
      } 
    });
  };

  // 그룹화 및 정렬
  const groupedByDate = filteredSentences.reduce((acc, sentence) => {
    const date = formatDateString(sentence.date);
    if (!acc[date]) {
      acc[date] = [];
    }
    acc[date].push(sentence);
    return acc;
  }, {} as Record<string, Sentence[]>);

  // 날짜 내림차순 정렬 (최신순)
  const sortedDates = Object.keys(groupedByDate).sort((a, b) => b.localeCompare(a));

  const renderSentenceCard = (s: Sentence) => (
    <div 
      key={s.id} 
      onClick={() => handleCardClick(s)}
      className="bg-white border border-gray-100 rounded-2xl p-4 shadow-sm flex items-start gap-4 hover:border-indigo-100 transition-colors cursor-pointer group/card"
    >
      <div className="flex-1">
        <div className="flex items-center gap-2 mb-1">
          <span className="text-[10px] font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded tracking-tight">
            {formatDateString(s.date)}
          </span>
          {s.bookmark && <Star className="w-3 h-3 fill-yellow-400 text-yellow-400" />}
        </div>
        <p className="text-gray-900 font-semibold mb-1 leading-tight group-hover/card:text-indigo-600 transition-colors">{s.sentence}</p>
        <p className="text-gray-500 text-sm">{s.meaning}</p>
      </div>
      <div className="flex flex-col gap-2" onClick={e => e.stopPropagation()}>
        {s.referenceUrl && (
          <a 
            href={s.referenceUrl}
            target="_blank"
            rel="noopener noreferrer"
            onClick={e => e.stopPropagation()}
            className="p-2 bg-indigo-50 rounded-full text-indigo-500 hover:bg-indigo-100 transition-colors flex items-center justify-center"
            title="참고 링크 열기"
          >
            <ExternalLink className="w-4 h-4" />
          </a>
        )}
        <button 
          onClick={() => navigate(`/edit/${s.id}`)}
          className="p-2 bg-gray-50 rounded-full text-gray-400 hover:text-indigo-500 hover:bg-indigo-50 transition-colors"
          title="수정"
        >
          <Edit2 className="w-4 h-4" />
        </button>
        <button 
          onClick={() => updateBookmarkOptimistically(s.id)}
          className={`p-2 rounded-full transition-colors ${s.bookmark ? 'text-yellow-500 bg-yellow-50' : 'text-gray-300 bg-gray-50'}`}
          title="북마크"
        >
          <Star className="w-4 h-4 fill-current" />
        </button>
      </div>
    </div>
  );

  return (
    <div className="pb-24 min-h-screen relative">
      <Header title={getTitle()} />

      <div className="px-4 pt-4 sticky top-[56px] bg-white/90 backdrop-blur-md z-20 pb-4 shadow-sm border-b border-gray-50">
        <button
          onClick={() => handleStartStudy()}
          disabled={filteredSentences.length === 0}
          className="w-full bg-indigo-600 text-white py-3.5 rounded-xl flex items-center justify-center gap-2 font-bold shadow-lg shadow-indigo-100 disabled:opacity-50 active:scale-95 transition-all"
        >
          <PlayCircle className="w-5 h-5" />
          전체 리스트 학습하기
        </button>
      </div>

      <div className="px-4 mt-6">
        {filteredSentences.length === 0 ? (
          <EmptyState />
        ) : (
          type === 'streak' || type === 'all' ? (
            <div className="space-y-10">
              {sortedDates.map(date => (
                <div key={date} className="space-y-4">
                  <div 
                    className="flex items-center gap-3 px-1 group cursor-pointer"
                    onClick={() => handleStartStudy(groupedByDate[date], `${date} 학습`)}
                  >
                    <div className="bg-slate-800 p-1.5 rounded-lg shadow-sm group-hover:bg-indigo-600 transition-colors">
                      <Calendar className="w-3.5 h-3.5 text-white" />
                    </div>
                    <div className="flex flex-col">
                      <h3 className="text-base font-black text-slate-800 tracking-tight leading-none mb-1 group-hover:text-indigo-600 transition-colors">{date}</h3>
                      <span className="text-[10px] font-bold text-slate-400">
                        {groupedByDate[date].length} 문장
                      </span>
                    </div>
                    <div className="h-[1px] flex-1 bg-gradient-to-r from-slate-200 to-transparent"></div>
                    <button
                      className="flex items-center gap-1 bg-indigo-50 text-indigo-600 px-3 py-1.5 rounded-full text-xs font-bold hover:bg-indigo-600 hover:text-white transition-all active:scale-95"
                    >
                      <Play className="w-3 h-3 fill-current" />
                      학습
                    </button>
                  </div>
                  <div className="space-y-3">
                    {groupedByDate[date].map(s => renderSentenceCard(s))}
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="space-y-3">
              {filteredSentences.map(s => renderSentenceCard(s))}
            </div>
